pub fn normalize_recovery_id(recovery_id_byte: u8) -> Result<u8, String> {
    match recovery_id_byte {
        0 | 1 => Ok(recovery_id_byte),
        27 | 28 => Ok(recovery_id_byte - 27),
        _ => Err(format!(
            "Invalid recovery ID byte: {} (expected 0, 1, 27, or 28)",
            recovery_id_byte
        )),
    }
